    <div className="max-w-4xl mx-auto">
      <motion.h2 className="text-4xl font-bold text-center mb-12">Frequently Asked Questions</motion.h2>
      <div className="space-y-6">
        {faqs.map((faq, i) => (
          <motion.div
            key={i}
